/**
 * Sanitize Prompt Inputs (ASI01 — Prompt Injection Prevention)
 */

const MAX_NAME = 80;
const MAX_MESSAGE = 500;
const MAX_HISTORY = 2000;
const MAX_FIELD = 120;

function sanitize(text, maxLen) {
  if (!text || typeof text !== 'string') return '';
  let s = text
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\b(ignore|oublie|forget|disregard)\s+(all\s+)?(previous|above|prior|preceding)\s+(instructions?|rules?|prompts?|context)/gi, '[FILTERED]')
    .replace(/\b(system|assistant|admin)\s*:/gi, '[FILTERED]')
    .replace(/\b(tu\s+es|you\s+are)\s+(now|maintenant|désormais)/gi, '[FILTERED]')
    .replace(/\bACT\s+AS\b/gi, '[FILTERED]')
    .replace(/\bRÈGLES?\s*:/gi, '[FILTERED]')
    .replace(/\bINSTRUCTION[S]?\s*:/gi, '[FILTERED]');
  if (s.length > maxLen) s = s.substring(0, maxLen) + '…';
  return s;
}

const input = $input.first().json;

const packages = $('Check Client Packages').first()?.json || [];
const subscriptions = $('Check Client Subscriptions').first()?.json || [];
const now = new Date().toISOString();

const activePackages = (Array.isArray(packages) ? packages : []).filter(cp => {
  if (!cp.package || !cp.package.is_active) return false;
  if (cp.expires_at && cp.expires_at < now) return false;
  return true;
});

const activeSubscriptions = Array.isArray(subscriptions) ? subscriptions : [];

let coverageSummary = 'aucun';
if (activePackages.length > 0 || activeSubscriptions.length > 0) {
  const parts = [];
  activePackages.forEach(cp => {
    parts.push(`Forfait "${cp.package.name}" (${cp.remaining_uses} séances restantes)`);
  });
  activeSubscriptions.forEach(sub => {
    parts.push(`Abonnement "${sub.name}" (actif)`);
  });
  coverageSummary = parts.join(', ');
}

return [{
  json: {
    ...input,
    safe_client_name: sanitize(input.client_name, MAX_NAME) || 'Inconnu',
    safe_message_text: sanitize(input.message_text, MAX_MESSAGE),
    safe_preferred_service: sanitize(input.preferred_service, MAX_FIELD) || 'aucun',
    safe_preferred_practitioner: sanitize(input.preferred_practitioner, MAX_FIELD) || 'aucun',
    safe_active_package: sanitize(coverageSummary, MAX_FIELD) || 'aucun',
    safe_conversation_history: sanitize(input.conversation_history, MAX_HISTORY) || 'Première interaction',
    safe_available_slots_text: sanitize(input.available_slots_text, MAX_HISTORY) || 'Aucun créneau chargé',
    safe_loyalty_points: Number(input.loyalty_points) || 0,
    safe_cancellation_delay: Number(input.cancellation_delay_minutes) || 120,
    has_active_coverage: activePackages.length > 0 || activeSubscriptions.length > 0
  }
}];

/**
 * Check AI Budget — vérifie si le commerçant a encore du budget tokens ce mois
 */
const merchantId = $input.first().json.merchant_id;
const supabaseUrl = $env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;

// 1. Récupérer le budget du commerçant
const merchantRes = await fetch(
  `${supabaseUrl}/rest/v1/merchants?id=eq.${merchantId}&select=ai_monthly_token_budget,ai_alert_email`,
  {
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`
    }
  }
);
const merchants = await merchantRes.json();
const budget = merchants[0]?.ai_monthly_token_budget || 100000;
const alertEmail = merchants[0]?.ai_alert_email || null;

// 2. Récupérer la conso du mois en cours
const startOfMonth = new Date();
startOfMonth.setDate(1);
startOfMonth.setHours(0, 0, 0, 0);

const usageRes = await fetch(
  `${supabaseUrl}/rest/v1/ai_token_usage?merchant_id=eq.${merchantId}&created_at=gte.${startOfMonth.toISOString()}&select=total_tokens`,
  {
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`
    }
  }
);
const usageRows = await usageRes.json();
const totalUsed = (Array.isArray(usageRows) ? usageRows : []).reduce((sum, r) => sum + (r.total_tokens || 0), 0);

const usagePercent = budget > 0 ? Math.round((totalUsed / budget) * 100) : 0;
const budgetExceeded = totalUsed >= budget;

return [{
  json: {
    ...$input.first().json,
    ai_budget: budget,
    ai_used_tokens: totalUsed,
    ai_usage_percent: usagePercent,
    ai_budget_exceeded: budgetExceeded,
    ai_alert_email: alertEmail
  }
}];

