/**
 * Parse Mistral Response — extrait la réponse + les tokens consommés
 */
const mistralOutput = $input.first().json;
const choice = mistralOutput.choices?.[0];
const usage = mistralOutput.usage || {};

let parsed;
try {
  const text = choice?.message?.content || '{}';
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    response_text: choice?.message?.content || 'Désolé, je n\'ai pas compris. Pouvez-vous reformuler ?',
    action: 'none',
    booking_data: {}
  };
}

return [{
  json: {
    ...$('Check AI Budget').first().json,
    response_text: parsed.response_text,
    action: parsed.action || 'none',
    booking_data: parsed.booking_data || {},
    // Token tracking
    llm_provider: 'mistral',
    llm_model: 'mistral-small-latest',
    llm_prompt_tokens: usage.prompt_tokens || 0,
    llm_completion_tokens: usage.completion_tokens || 0,
    llm_total_tokens: usage.total_tokens || 0,
    llm_is_fallback: true,
    llm_error: null
  }
}];

/**
 * Static Fallback — message prédéfini quand les 2 LLMs sont down ou budget épuisé
 */
const context = $('Check AI Budget').first().json;
const budgetExceeded = context.ai_budget_exceeded;

let message;
if (budgetExceeded) {
  message = 'Bonjour ! Notre assistant est temporairement indisponible. ' +
    'Veuillez nous contacter directement par téléphone pour prendre rendez-vous. ' +
    'Nous nous excusons pour la gêne occasionnée.';
} else {
  message = 'Bonjour ! Notre assistant rencontre un problème technique. ' +
    'Un conseiller vous recontactera dans les plus brefs délais. ' +
    'Nous nous excusons pour la gêne occasionnée.';
}

return [{
  json: {
    ...context,
    response_text: message,
    action: 'none',
    booking_data: {},
    // Token tracking
    llm_provider: 'static',
    llm_model: 'static-fallback',
    llm_prompt_tokens: 0,
    llm_completion_tokens: 0,
    llm_total_tokens: 0,
    llm_is_fallback: true,
    llm_error: budgetExceeded ? 'budget_exceeded' : 'both_llms_down'
  }
}];

/**
 * Log Token Usage — enregistre la consommation tokens dans Supabase
 */
const data = $input.first().json;
const supabaseUrl = $env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;

// Calcul du coût en EUR
const PRICING = {
  'gemini': { prompt: 0.075 / 1_000_000, completion: 0.30 / 1_000_000 },
  'mistral': { prompt: 0.10 / 1_000_000, completion: 0.30 / 1_000_000 },
  'static': { prompt: 0, completion: 0 }
};

const pricing = PRICING[data.llm_provider] || PRICING.static;
const costEur = (data.llm_prompt_tokens * pricing.prompt) + (data.llm_completion_tokens * pricing.completion);

// INSERT dans ai_token_usage
const insertRes = await fetch(`${supabaseUrl}/rest/v1/ai_token_usage`, {
  method: 'POST',
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: JSON.stringify({
    merchant_id: data.merchant_id,
    conversation_id: data.conversation_id || null,
    model: data.llm_model,
    provider: data.llm_provider,
    prompt_tokens: data.llm_prompt_tokens,
    completion_tokens: data.llm_completion_tokens,
    total_tokens: data.llm_total_tokens,
    cost_eur: costEur,
    is_fallback: data.llm_is_fallback,
    error_message: data.llm_error
  })
});

// Calculer le nouveau total du mois pour les alertes
const newTotal = (data.ai_used_tokens || 0) + (data.llm_total_tokens || 0);
const budget = data.ai_budget || 100000;
const newPercent = budget > 0 ? Math.round((newTotal / budget) * 100) : 0;

// Détection anomalie : moyenne des 7 derniers jours
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

const avgRes = await fetch(
  `${supabaseUrl}/rest/v1/ai_token_usage?merchant_id=eq.${data.merchant_id}&created_at=gte.${sevenDaysAgo.toISOString()}&select=total_tokens`,
  {
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`
    }
  }
);
const avgRows = await avgRes.json();
const totalLast7Days = (Array.isArray(avgRows) ? avgRows : []).reduce((s, r) => s + (r.total_tokens || 0), 0);
const dailyAvg = totalLast7Days / 7;
const todayStart = new Date();
todayStart.setHours(0, 0, 0, 0);

const todayRes = await fetch(
  `${supabaseUrl}/rest/v1/ai_token_usage?merchant_id=eq.${data.merchant_id}&created_at=gte.${todayStart.toISOString()}&select=total_tokens`,
  {
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`
    }
  }
);
const todayRows = await todayRes.json();
const todayTotal = (Array.isArray(todayRows) ? todayRows : []).reduce((s, r) => s + (r.total_tokens || 0), 0);
const isAnomaly = dailyAvg > 0 && todayTotal > (dailyAvg * 3);

// Déterminer le niveau d'alerte
let alertLevel = 'none';
if (isAnomaly) alertLevel = 'anomaly';
else if (newPercent >= 100) alertLevel = 'critical';
else if (newPercent >= 95) alertLevel = 'warning';
else if (newPercent >= 80) alertLevel = 'info';

return [{
  json: {
    ...data,
    token_log_cost_eur: costEur,
    token_log_new_total: newTotal,
    token_log_new_percent: newPercent,
    token_log_alert_level: alertLevel,
    token_log_is_anomaly: isAnomaly,
    token_log_daily_avg: Math.round(dailyAvg)
  }
}];
